#!/bin/bash
set -e
echo '🎮 Deploying GACOM Arena — all files...'
mkdir -p lib/features/arena/services
mkdir -p lib/features/arena/screens/games
mkdir -p lib/features/arena/widgets
mkdir -p supabase/functions/arena-payout
mkdir -p supabase/migrations

echo '  ✅ lib/features/arena/services/arena_service.dart'
echo '' | base64 -d > lib/features/arena/services/arena_service.dart

echo '  ✅ lib/features/arena/screens/arena_screen.dart'
echo '' | base64 -d > lib/features/arena/screens/arena_screen.dart

echo '  ✅ lib/features/arena/screens/match_screen.dart'
echo '' | base64 -d > lib/features/arena/screens/match_screen.dart

echo '  ✅ lib/features/arena/screens/games/tictactoe_game.dart'
echo '' | base64 -d > lib/features/arena/screens/games/tictactoe_game.dart

echo '  ✅ lib/features/arena/screens/games/rps_game.dart'
echo '' | base64 -d > lib/features/arena/screens/games/rps_game.dart

echo '  ✅ lib/features/arena/screens/games/trivia_game.dart'
echo '' | base64 -d > lib/features/arena/screens/games/trivia_game.dart

echo '  ✅ lib/features/arena/screens/games/reaction_game.dart'
echo '' | base64 -d > lib/features/arena/screens/games/reaction_game.dart

echo '  ✅ lib/features/arena/screens/games/chess_game.dart'
echo 'ZXhwb3J0ICdyZWFjdGlvbl9nYW1lLmRhcnQnIHNob3cgQ2hlc3NHYW1lOwo=' | base64 -d > lib/features/arena/screens/games/chess_game.dart

echo '  ✅ lib/features/arena/screens/arena_admin_section.dart'
echo '' | base64 -d > lib/features/arena/screens/arena_admin_section.dart

echo '  ✅ supabase/migrations/007_arena_schema.sql'
echo '' | base64 -d > supabase/migrations/007_arena_schema.sql

echo '  ✅ supabase/functions/arena-payout/index.ts'
echo '' | base64 -d > supabase/functions/arena-payout/index.ts

echo ''
echo '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
echo '✅ Arena files written!'
echo ''
echo 'Now do these manually:'
echo ''
echo '1. Add to router_service.dart imports:'
echo "   import '../../features/arena/screens/arena_screen.dart';"
echo "   import '../../features/arena/screens/match_screen.dart';"
echo ''
echo '2. Add route to ShellRoute (after storeRoute):'
echo "   GoRoute(path: '/arena', builder: (_, __) => const ArenaScreen(),'"
echo "     routes: [GoRoute(path: 'match/:id', builder: (_, s) => MatchScreen(matchId: s.pathParameters['id']!))]),'"
echo ''
echo '3. Add to AppConstants: static const arenaRoute = "/arena";'
echo ''
echo '4. Add to admin dashboard _sections: "Arena"'
echo '   Add case 8: return const ArenaAdminSection(); to _buildSection()'
echo '   Add import for arena_admin_section.dart'
echo ''
echo '5. Add Arena tab to main_shell.dart _tabs:'
echo "   _Tab(icon: Icons.sports_esports_rounded, label: 'Arena', route: '/arena'),"
echo ''
echo '6. Run SQL in Supabase SQL editor (supabase/migrations/007_arena_schema.sql)'
echo ''
echo '7. Deploy edge function:'
echo '   npx supabase functions deploy arena-payout --no-verify-jwt'
echo ''
echo '8. Add Metered TURN creds in lib/features/arena/services/arena_service.dart'
echo '   Find turnServers const and add your username + credential'
echo ''
echo '9. Push:'
echo '   git add lib/ supabase/ && git commit -m "feat: GACOM Arena" && git push origin main'
echo '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
